import { NavLink, Outlet, useNavigate } from "react-router-dom";

const navItems = [
  { to: "/dashboard", label: "Dashboard" },
  { to: "/customers", label: "Customers" },
  { to: "/add", label: "Add Customer" },
  { to: "/attendance", label: "Attendance" }
];

export default function AppShell() {
  const navigate = useNavigate();
  const todayLabel = new Intl.DateTimeFormat("en-US", {
    dateStyle: "full"
  }).format(new Date());

  const handleLogout = () => {
    localStorage.removeItem("token");
    navigate("/login");
  };

  return (
    <div className="app-shell">
      <aside className="app-shell__sidebar">
        <div>
          <div className="brand-mark">PulseFit</div>
          <h1>Gym operations, without the spreadsheet drag.</h1>
          <p className="app-shell__intro">Track members, renewals, and attendance.</p>
        </div>

        <nav className="app-shell__nav" aria-label="Primary">
          {navItems.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              className={({ isActive }) =>
                `app-shell__nav-link${isActive ? " is-active" : ""}`
              }
            >
              {item.label}
            </NavLink>
          ))}
        </nav>

        <div className="app-shell__sidebar-note">
          <span className="sidebar-note__label">Today</span>
          <strong>{todayLabel}</strong>
          <span>Keep renewals and check-ins moving.</span>
        </div>
      </aside>

      <div className="app-shell__main">
        <header className="app-shell__header">
          <div>
            <span className="eyebrow">Front desk console</span>
            <p className="app-shell__header-copy">Simple frontend flow with mock data.</p>
          </div>

          <button className="button button--ghost" onClick={handleLogout}>
            Log out
          </button>
        </header>

        <main className="app-shell__content">
          <Outlet />
        </main>
      </div>
    </div>
  );
}
